import client from './client'
import type { AdminUser } from '@/types/auth'

export interface UsersResponse {
  users: AdminUser[]
}

export interface UserResponse {
  user: AdminUser
}

export interface ActionResponse {
  message: string
  user: AdminUser
}

export const adminApi = {
  listUsers: () => client.get<UsersResponse>('/api/v1/admin/users'),

  getUser: (id: string) => client.get<UserResponse>(`/api/v1/admin/users/${id}`),

  deactivateUser: (id: string) =>
    client.patch<ActionResponse>(`/api/v1/admin/users/${id}/deactivate`),

  activateUser: (id: string) =>
    client.patch<ActionResponse>(`/api/v1/admin/users/${id}/activate`),
}

import { useEffect, useState } from 'react'
import { toast } from 'sonner'
import { AppSidebar } from '@/components/app-sidebar'
import { Button } from '@/components/ui/button'
import { adminApi } from '@/api/admin'
import type { AdminUser } from '@/types/auth'

export function UsersPage() {
  const [users, setUsers] = useState<AdminUser[]>([])
  const [loading, setLoading] = useState(true)
  const [actionInProgress, setActionInProgress] = useState<string | null>(null)

  useEffect(() => {
    adminApi
      .listUsers()
      .then(({ data }) => setUsers(data.users))
      .catch(() => toast.error('Failed to load users'))
      .finally(() => setLoading(false))
  }, [])

  async function handleDeactivate(user: AdminUser) {
    setActionInProgress(user.id)
    try {
      const { data } = await adminApi.deactivateUser(user.id)
      setUsers((prev) => prev.map((u) => (u.id === user.id ? data.user : u)))
      toast.success(`${user.email} deactivated`)
    } catch (err: unknown) {
      const msg =
        err && typeof err === 'object' && 'error' in err
          ? String((err as { error: string }).error)
          : 'Failed to deactivate user'
      toast.error(msg)
    } finally {
      setActionInProgress(null)
    }
  }

  async function handleActivate(user: AdminUser) {
    setActionInProgress(user.id)
    try {
      const { data } = await adminApi.activateUser(user.id)
      setUsers((prev) => prev.map((u) => (u.id === user.id ? data.user : u)))
      toast.success(`${user.email} activated`)
    } catch (err: unknown) {
      const msg =
        err && typeof err === 'object' && 'error' in err
          ? String((err as { error: string }).error)
          : 'Failed to activate user'
      toast.error(msg)
    } finally {
      setActionInProgress(null)
    }
  }

  return (
    <AppSidebar>
      <div className="space-y-6">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Users</h2>
          <p className="text-muted-foreground">Manage platform user accounts</p>
        </div>

        {loading ? (
          <p className="text-sm text-muted-foreground">Loading...</p>
        ) : (
          <div className="rounded-md border">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b bg-muted/50">
                  <th className="px-4 py-3 text-left font-medium">Email</th>
                  <th className="px-4 py-3 text-left font-medium">Role</th>
                  <th className="px-4 py-3 text-left font-medium">Verified</th>
                  <th className="px-4 py-3 text-left font-medium">Status</th>
                  <th className="px-4 py-3 text-left font-medium">Created</th>
                  <th className="px-4 py-3 text-left font-medium">Actions</th>
                </tr>
              </thead>
              <tbody>
                {users.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="px-4 py-6 text-center text-muted-foreground">
                      No users found
                    </td>
                  </tr>
                ) : (
                  users.map((user) => (
                    <tr key={user.id} className="border-b last:border-0 hover:bg-muted/25">
                      <td className="px-4 py-3 font-mono text-xs">{user.email}</td>
                      <td className="px-4 py-3">
                        <span
                          className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
                            user.role === 'admin'
                              ? 'bg-purple-100 text-purple-800'
                              : 'bg-gray-100 text-gray-700'
                          }`}
                        >
                          {user.role}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
                            user.email_verified
                              ? 'bg-green-100 text-green-800'
                              : 'bg-yellow-100 text-yellow-800'
                          }`}
                        >
                          {user.email_verified ? 'Verified' : 'Unverified'}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
                            user.deactivated
                              ? 'bg-red-100 text-red-800'
                              : 'bg-green-100 text-green-800'
                          }`}
                        >
                          {user.deactivated ? 'Deactivated' : 'Active'}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-muted-foreground">
                        {new Date(user.created_at).toLocaleDateString()}
                      </td>
                      <td className="px-4 py-3">
                        {user.deactivated ? (
                          <Button
                            size="sm"
                            variant="outline"
                            disabled={actionInProgress === user.id}
                            onClick={() => handleActivate(user)}
                          >
                            Activate
                          </Button>
                        ) : (
                          <Button
                            size="sm"
                            variant="outline"
                            className="text-red-600 hover:text-red-700 hover:bg-red-50"
                            disabled={actionInProgress === user.id}
                            onClick={() => handleDeactivate(user)}
                          >
                            Deactivate
                          </Button>
                        )}
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </AppSidebar>
  )
}
